previewCss:
.darma-loader-darma-custom-133 {
  color: var(--loader-color, #2563eb);
width: 49px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color, #60a5fa));
background:
var(--c) 0 0,
var(--c) 0 100%,
var(--c) 50% 50%,  
 var(--c) 100% 0,
var(--c) 100% 100%;
animation: darma-loader-darma-custom-133-l13 1s infinite alternate;
}

@keyframes darma-loader-darma-custom-133-l13 {
0%,10% {background-size:20% 100%}
50% {background-size:20% 20%}
90%,100% {background-size:100% 20%}
}

